const msgData = $('Parse Twilio Data').first().json;
let messageBody = msgData.body || '';
try {
  const t = $('Whisper Transcribe').first().json.text;
  if (t && t.trim()) messageBody = t.trim();
} catch(e) {}
const customerPhone = msgData.customer_phone;
const numMedia = parseInt(msgData.num_media) || 0;
const isVoiceMsg = String(msgData.media_content_type || '').startsWith('audio');
const visualMedia = isVoiceMsg ? 0 : numMedia;
const mediaUrl = msgData.media_url || '';

let activeConv = null;
try {
  const convItems = $('Get Active Conversation').all();
  let latest = null;
  for (const it of convItems) {
    const c = it.json;
    if (!c || !c.last_message_at) continue;
    if (!latest || new Date(c.last_message_at) > new Date(latest.last_message_at)) latest = c;
  }
  if (latest) {
    const hoursDiff = (Date.now() - new Date(latest.last_message_at).getTime()) / 3600000;
    if (hoursDiff < 24) activeConv = latest;
  }
} catch(e) {}

let stateDataRaw = activeConv ? (activeConv.state_data || {}) : {};
let pi = 0;
while (typeof stateDataRaw === 'string' && pi < 10) {
  try { stateDataRaw = JSON.parse(stateDataRaw); } catch(e) { stateDataRaw = {}; break; }
  pi++;
}
const stateData = (typeof stateDataRaw === 'object' && stateDataRaw !== null) ? stateDataRaw : {};

const messages = stateData.messages || [];
const extracted = stateData.extracted || {};
const extractedStr = JSON.stringify(extracted, null, 2);
const activeCallId = activeConv ? activeConv.active_call_id : null;

let userContent = messageBody || '';
if (visualMedia > 0) userContent = (userContent ? userContent + '\n' : '') + '[הלקוח שלח תמונה/קובץ]';
if (!userContent) userContent = '(פנה ללא טקסט)';

const israelTime = new Date(Date.now() + 3 * 60 * 60 * 1000);
const dow = israelTime.getUTCDay();
const totalMin = israelTime.getUTCHours() * 60 + israelTime.getUTCMinutes();
const isOpen = dow >= 0 && dow <= 4 && totalMin >= 450 && totalMin < 1020;

let officeHoursNote = '';
if (!isOpen) {
  const nextOpen = (dow === 4 && totalMin >= 1020) || dow === 5 || dow === 6 ? 'ביום ראשון הקרוב' : 'מחר בבוקר';
  officeHoursNote = '\n\nהמשרד סגור כרגע (שעות פתיחה ראשון-חמישי 7:30-17:00). כשתפתח קריאה, ציין שנציג ייצור קשר ' + nextOpen + '. עדיין פתח קריאה כרגיל.';
}

let activeCallNote = '';
if (activeCallId) activeCallNote = '\n\nקריאה #' + activeCallId + ' כבר פתוחה. אם עדכון - ענה בחיוב שהמשרד יעדכן.';

const businessInfo = '\n\nמידע על אבוקה: כתובת: דרך בר יהודה 113 נשר | וייז: https://ul.waze.com/ul?venue_id=22937928.229706957.34438&overview=yes | שעות: ראשון-חמישי 7:30-17:00 | טלפון: 04-8212912';

const systemPrompt = 'אתה עוזר שירות לקוחות של חברת אבוקה - חברה ישראלית לכיבוי אש, ספרינקלרים ובטיחות.\n\nמשימה: שיחה ידידותית בעברית לאיסוף פרטי פנייה והעברתה למשרד.\n\nטון: חם, נחמד ומזמין - כמו נציג אנושי שמח לעזור. שלב אימוג\'ים בודדים ומתאימים (כמו 😊 🙏 🔧) כדי שיהיה נעים, אבל בלי להגזים - אימוג\'י אחד פה ושם, לא בכל שורה.\n\nפרטים לאיסוף: customer_name, company, address, description, urgency (high/low/normal).\n\nסיווג הפנייה (intent) - סווג כל שיחה לאחד מאלה:\n- malfunction = תקלה/בעיה טכנית/דליפה/מערכת לא תקינה\n- quote = בקשת הצעת מחיר/עלות\n- certificate = בקשת אישור/אסמכתא/תעודה/מסמך\n- general_question = שאלה כללית/מידע/שעות/כתובת\n\nכללים:\n1. שיחה טבעית, חמה וקצרה - לא רובוטית.\n2. חלץ את כל הפרטים שהלקוח כבר נתן - קרא היטב את כל היסטוריית השיחה לפני שאתה שואל.\n3. אשר ללקוח בחום שהבנת את הבעיה במשפט קצר לפני שאתה ממשיך (למשל: הבנתי, נזילה מספרינקלר במפעל - נדאג לטפל בזה). אל תזכיר דחיפות.\n4. שאל רק פרטים שעדיין חסרים. אם חסרים כמה פרטים - שאל את כולם יחד בהודעה אחת, לא אחד-אחד. אם הלקוח כבר תיאר את התקלה - אל תשאל שוב מה הבעיה. אם כבר נתן כתובת - אל תבקש כתובת.\n5. הפרטים הדרושים: שם, חברה (אם יש), כתובת, תיאור התקלה.\n6. חובה: מלא את extracted_data בכל הפרטים הידועים מכל השיחה (customer_name, company, address, description, urgency). אם פרט נאמר אי-פעם בשיחה - שים אותו ב-extracted_data, אל תשאיר null.\n7. אל תחזור לעולם על שאלה שכבר נענתה, גם לא בניסוח אחר.\n8. ברגע שיש שם, כתובת ותיאור - עבור מיד לסיכום, אל תשאל שום שאלה נוספת לפני הסיכום. אם הגיעה תמונה כשכל הפרטים כבר ידועים - הצג את הסיכום מיד באותה תשובה, אל תשאל שוב במה מדובר.\n9. הצג סיכום ובקש אישור (שם, חברה, כתובת, תיאור). אם הלקוח עדיין לא שלח תמונה ולא התייחס לכך - סיים את הודעת הסיכום בשורה: אם יש לך תמונה של התקלה, אפשר לצרף אותה עכשיו 📷. אל תציג דחיפות ללקוח.\n10. חובה: כשהלקוח מאשר את הסיכום (כן / נכון / מאשר / אפשר / סבבה / בסדר) - החזר should_create_call: true וקבע intent מתאים. אל תאשר פתיחה בלי should_create_call: true.\n11. אסור להודיע ללקוח שנפתחה קריאה או שהפנייה הועברה למשרד אלא אם should_create_call=true באותה תשובה בדיוק. אם response_text מודיע על פתיחת קריאה - should_create_call חייב להיות true.\n12. ענה בעברית. urgency הוא שדה פנימי בלבד - לעולם אל תזכיר ללקוח דחיפות, אל תכתוב דחוף או לא דחוף בשום הודעה, כולל באישור ההבנה ובסיכום.\n13. נסח את אישור הסיכום לפי סוג הפנייה: לתקלה - נפתחה קריאת שירות ונציג ייצור קשר; להצעת מחיר/אישור/שאלה - הפנייה הועברה למשרד ונציג יחזור אליך. אל תפנה לטלפון המשרד.' + activeCallNote + officeHoursNote + businessInfo + '\n\nמידע שנאסף עד כה (extracted): ' + extractedStr + '\n\nכלל פורמט: אל תשתמש בגרשיים כפולים בתוך response_text.\n\nענה ONLY ב-JSON:\n{"response_text":"טקסט ללקוח","extracted_data":{"customer_name":null,"company":null,"address":null,"description":null,"urgency":"normal"},"intent":"malfunction","should_create_call":false}';

return [{json: {
  system_prompt: systemPrompt,
  api_messages_json: JSON.stringify([...messages.slice(-10), { role: 'user', content: userContent }]),
  customer_phone: customerPhone,
  conversation_id: activeConv ? activeConv.id : null,
  has_active_conv: !!activeConv,
  current_state_data_json: JSON.stringify(stateData),
  new_user_message: userContent,
  num_media: visualMedia,
  media_url: mediaUrl,
  active_call_id: activeCallId,
  is_office_open: isOpen,
}}];

const buildData = $('Build AI Context').first().json;
const apiResult = $('Call Claude API').first().json;
const rawText = (apiResult.content?.[0]?.text || '').trim();
let claudeData = { response_text: '', extracted_data: {}, should_create_call: false };

if (!rawText) {
  claudeData.response_text = 'מצטער, הייתה שגיאה זמנית. תנסה שוב.';
} else {
  let parsed = false;
  const candidates = [rawText, rawText.replace(/```json\n?|```\n?/g,'').trim()];
  for (const c of candidates) {
    try { claudeData = JSON.parse(c); parsed = true; break; } catch(e) {}
  }
  if (!parsed) {
    try {
      const m = rawText.match(/"response_text"\s*:\s*"([\s\S]*?)"\s*,\s*"extracted_data"/);
      if (m) {
        const rt = m[1].replace(/\\n/g, '\n');
        const rest = rawText.substring(rawText.indexOf('"extracted_data"'));
        try {
          const partial = JSON.parse('{' + rest + '}');
          claudeData = { response_text: rt, extracted_data: partial.extracted_data || {}, should_create_call: partial.should_create_call === true };
        } catch(e) { claudeData = { response_text: rt, extracted_data: {}, should_create_call: false }; }
        parsed = true;
      }
    } catch(e) {}
  }
  if (!parsed) claudeData = { response_text: rawText, extracted_data: {}, should_create_call: false };
}

const extracted = claudeData.extracted_data || {};
const prevStateData = JSON.parse(buildData.current_state_data_json || '{}');
const prevExtracted = prevStateData.extracted || {};
const prevMessages = prevStateData.messages || [];
const prevAttachments = prevStateData.attachments || [];

const mergedExtracted = {
  customer_name: extracted.customer_name || prevExtracted.customer_name || null,
  company: extracted.company || prevExtracted.company || null,
  address: extracted.address || prevExtracted.address || null,
  description: extracted.description || prevExtracted.description || null,
  urgency: extracted.urgency || prevExtracted.urgency || 'normal',
};

const responseText = claudeData.response_text || 'מצטער, לא הצלחתי לעבד. תנסה שוב.';
const updatedMessages = [...prevMessages, { role: 'user', content: buildData.new_user_message }, { role: 'assistant', content: responseText }].slice(-20);

const updatedAttachments = [...prevAttachments];
try {
  const up = $('Upload Image to Base44').first().json;
  const url = up && (up.file_url || up.url || (up.data && up.data.file_url));
  if (url) updatedAttachments.push({ url, type: 'image' });
} catch(e) {}

const newStateData = { messages: updatedMessages, extracted: mergedExtracted, attachments: updatedAttachments };
let shouldCreateCall = claudeData.should_create_call === true;
// Guard: אם המודל הודיע ללקוח שנפתחה קריאה/הפנייה הועברה אבל שכח את הדגל - מיישרים לפי ההודעה
if (!shouldCreateCall) {
  const announced = /נפתחה קריאת שירות|נפתחה קריאה|הפנייה הועברה למשרד|העברתי את הפנייה|הפנייה נקלטה/.test(responseText);
  const hasDetails = !!(mergedExtracted.description && mergedExtracted.address && mergedExtracted.customer_name);
  if (announced && hasDetails) shouldCreateCall = true;
}
const fullName = mergedExtracted.customer_name ? (mergedExtracted.company ? mergedExtracted.customer_name + ' - ' + mergedExtracted.company : mergedExtracted.customer_name) : '';

return [{json: {
  has_active_conv: buildData.has_active_conv,
  conversation_id: buildData.conversation_id,
  next_state: shouldCreateCall ? 'completed' : 'in_progress',
  state_data_json: JSON.stringify(newStateData),
  response_text: responseText,
  should_create_call: shouldCreateCall,
  urgency: mergedExtracted.urgency || 'normal',
  customer_name: fullName,
  address: mergedExtracted.address || '',
  description: mergedExtracted.description || '',
  customer_phone: buildData.customer_phone,
  active_call_id: buildData.active_call_id,
  is_office_open: buildData.is_office_open,
  attachments: updatedAttachments,
  attachments_count: updatedAttachments.length,
}}];

