const id = $('Create Service Call').first().json.id;
const atts = $('Parse AI Response').first().json.attachments || [];
if (!atts.length) return [];
return atts.map(a => ({ json: { service_call_id: id, file_url: a.url, file_type: a.type || 'image' } }));

const p = $('Parse AI Response').first().json;
let custId = '';
try {
  const items = $('Lookup Customer (Base44)').all();
  if (items.length && items[0].json && items[0].json.id) custId = items[0].json.id;
} catch(e) {}
const today = new Date(Date.now() + 3*3600*1000).toISOString().slice(0,10);
const isUrgent = (p.urgency === 'high' || p.urgency === 'urgent');
const images = (p.attachments || []).map(a => a && a.url).filter(Boolean);
return [{ json: {
  identified: !!custId,
  customer_id: custId,
  call_type: isUrgent ? 'urgent_malfunction' : 'malfunction',
  department: 'service',
  open_date: today,
  problem_description: p.description || '',
  customer_name: p.customer_name || '',
  address: p.address || '',
  phone: (p.customer_phone||'').replace('whatsapp:','').replace('+972','0'),
  urgency_inq: isUrgent ? 'urgent' : 'normal',
  images
} }];

const raw = ((($('Call Claude API').first().json.content) || [])[0]?.text || '').trim();
let intent = 'malfunction';
try {
  const c = raw.replace(/```json/g,'').replace(/```/g,'').trim();
  const o = JSON.parse(c);
  if (o && o.intent) intent = o.intent;
} catch(e) {}
return [{ json: { ...$('Parse AI Response').first().json, intent } }];

const p = $('Parse AI Response').first().json;
const it = $('Extract Intent').first().json.intent;
const map = { quote: 'quote', certificate: 'other', general_question: 'general_question' };
const inquiry_type = map[it] || 'other';
const isUrgent = (p.urgency === 'high' || p.urgency === 'urgent');
const images = (p.attachments || []).map(a => a && a.url).filter(Boolean);
return [{ json: {
  customer_name: p.customer_name || '',
  phone: (p.customer_phone || '').replace('whatsapp:','').replace('+972','0'),
  address: p.address || '',
  description: p.description || '',
  inquiry_type,
  urgency_inq: isUrgent ? 'urgent' : 'normal',
  images
} }];
